import{_ as o,o as t,c,a2 as a}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"Hexo 블로그 92편을 VitePress 로 한 번에 이관하기 — 멱등 임포터","description":"","frontmatter":{"slug":"hexo-blog-import","title":"Hexo 블로그 92편을 VitePress 로 한 번에 이관하기 — 멱등 임포터","authors":[],"tags":["hexo","vitepress","content-migration","automation","spec-kit","tooling"],"created":"2026-06-02 17:49 (KST)","date":"2026-06-02T08:49:00.000Z"},"headers":[],"relativePath":"journal/2026-06-02-hexo-blog-import.md","filePath":"journal/2026-06-02-hexo-blog-import.md","lastUpdated":1781092690000}'),d={name:"journal/2026-06-02-hexo-blog-import.md"};function i(r,e,l,s,n,g){return t(),c("div",null,[...e[0]||(e[0]=[a('<p>옛 Hexo 블로그(<code>../coffeeman1-main</code>)의 글 <strong>92편 · 이미지 554장</strong>을 현재 VitePress 사이트의 <code>/blog-archive/</code> 섹션으로 한 번의 명령에 이관했다. Spec Kit 사이클(specify → clarify → plan → tasks → analyze → implement)을 그대로 타고 <code>feature 008</code> 로 진행했다.</p><h2 id="무엇이-문제였나" tabindex="-1">무엇이 문제였나 <a class="header-anchor" href="#무엇이-문제였나" aria-label="Permalink to &quot;무엇이 문제였나&quot;">​</a></h2><p>두 시스템의 형식이 달라 손으로 옮기면 재현이 안 된다.</p><ul><li><strong>프런트매터</strong>: Hexo 는 <code>category:</code>(단수!) 에 <code>[Coding,java]</code>·한글 <code>[설치,PHP]</code> 같은 값을 쓴다. <code>title</code> 에 콜론이 박혀 있기도 하다.</li><li><strong>이미지</strong>: 글별 asset 폴더 · 전역 <code>images/</code>·<code>img/</code> · <code>../../images/x</code>(사이트 루트 기준) · <code>{% asset_img %}</code> 4가지가 섞여 있다.</li><li><strong>Hexo 전용 태그</strong>: <code>{% asset_img %}</code>(261) · <code>{% fa %}</code>(72) · <code>{% callout %}</code> (11쌍) · <code>{% incl %}</code>(16) · <code>{% draw %}</code>(3) · <code>{% iframe %}</code>(1).</li></ul><h2 id="어떻게-풀었나" tabindex="-1">어떻게 풀었나 <a class="header-anchor" href="#어떻게-풀었나" aria-label="Permalink to &quot;어떻게 풀었나&quot;">​</a></h2><p>의존성 0의 단일 Node 스크립트(<code>scripts/import-hexo-blog.mjs</code>)로 변환 파이프라인을 구성했다. 핵심은 <strong>코드펜스/인라인코드 밖에서만</strong> 치환하는 헬퍼다 — 덕분에 &quot;Hexo 문법을 설명하는 글&quot;의 <code>```html `{% fa %}`</code> 예시는 리터럴로 보존되고, 본문의 <code>{% fa user %}</code> 만 👤 로 바뀐다.</p><ul><li><code>{% asset_img %}</code>→마크다운 이미지, <code>{% fa %}</code>→이모지, <code>{% callout %}</code>→VitePress 컨테이너(<code>::: tip/warning</code>), <code>{% incl %}</code>→공용 조각 재귀 인라인, <code>{% draw %}</code>/ <code>{% iframe %}</code>→링크/<code>&lt;iframe&gt;</code>. 메뉴 라벨은 영문으로 통일.</li><li>멱등: <code>blog-archive/**</code> 와 사이드바를 매 실행 전량 재생성 → 2회 연속 실행 시 산출물 SHA 동일.</li></ul><h2 id="strict-빌드가-가르쳐-준-함정-최신순" tabindex="-1">strict 빌드가 가르쳐 준 함정 (최신순) <a class="header-anchor" href="#strict-빌드가-가르쳐-준-함정-최신순" aria-label="Permalink to &quot;strict 빌드가 가르쳐 준 함정 (최신순)&quot;">​</a></h2><ol><li><strong><code>&lt;&lt;&lt; @/path</code></strong> — Hexo 글에 리터럴로 들어 있던 문자열이 하필 VitePress 의 <strong>코드 스니펫 임포트 문법</strong>이라, 없는 파일을 <code>statSync</code> 하다 빌드가 죽었다. 줄머리 <code>&lt;&lt;&lt;</code> 를 인라인 코드로 무력화.</li><li><strong><code>{% iframe ... 100% ... %}</code></strong> — 값 안의 <code>%</code> 때문에 <code>%</code> 를 배제한 정규식이 태그를 못 잡았다. <code>%}</code> 를 비탐욕 종결자로 잡는 단일 디스패처로 교체.</li><li><strong><code>http://localhost:8080/...</code></strong> — 튜토리얼 글에 깔린 예시 URL 을 dead-link 검사가 잡았다. <code>ignoreDeadLinks: &#39;localhostLinks&#39;</code> 로 localhost 만 제외(나머지 strict 유지). 해석 불가 내부 링크는 옛 사이트 URL 로 외부화.</li></ol><p>최종적으로 <strong>dead link 0 · 잔여 Hexo 태그 0(코드 밖) · 빌드 성공</strong>. 단위 테스트 15개로 변환 규칙을 고정했다.</p><h2 id="메모" tabindex="-1">메모 <a class="header-anchor" href="#메모" aria-label="Permalink to &quot;메모&quot;">​</a></h2><ul><li>생성물(<code>blog-archive/**</code>)은 커밋해 CI 가 소비한다. 임포터는 <code>../coffeeman1-main</code> 을 읽으므로 CI 에서 돌지 않는다 — 로컬에서 돌려 결과를 커밋하는 도구다.</li><li>원본은 한 바이트도 건드리지 않았다(읽기 전용).</li></ul>',12)])])}const p=o(d,[["render",i]]);export{h as __pageData,p as default};
